app.post('/api/advanced-search', async (req: Request, res: Response) => {
  try {
    const { filters, orderBy, limit, offset } = req.body;
    const conditions: string[] = [];
    const values: any[] = [];
    let paramIndex = 1;

    if (filters && Array.isArray(filters)) {
      for (const filter of filters) {
        const { field, operator, value } = filter;
        
        switch (operator) {
          case 'equals':
            conditions.push(`${field} = $${paramIndex}`);
            values.push(value);
            paramIndex++;
            break;
          case 'contains':
            conditions.push(`${field} ILIKE $${paramIndex}`);
            values.push(`%${value}%`);
            paramIndex++;
            break;
          case 'starts_with':
            conditions.push(`${field} ILIKE $${paramIndex}`);
            values.push(`${value}%`);
            paramIndex++;
            break;
          case 'ends_with':
            conditions.push(`${field} ILIKE $${paramIndex}`);
            values.push(`%${value}`);
            paramIndex++;
            break;
          case 'greater_than':
            conditions.push(`${field} > $${paramIndex}`);
            values.push(value);
            paramIndex++;
            break;
          case 'less_than':
            conditions.push(`${field} < $${paramIndex}`);
            values.push(value);
            paramIndex++;
            break;
          case 'in':
            const placeholders = value.map((_: any, i: number) => `$${paramIndex + i}`).join(', ');
            conditions.push(`${field} IN (${placeholders})`);
            values.push(...value);
            paramIndex += value.length;
            break;
        }
      }
    }

    let query = 'SELECT * FROM users';
    
    if (conditions.length > 0) {
      query += ` WHERE ${conditions.join(' AND ')}`;
    }

    if (orderBy) {
      query += ` ORDER BY ${orderBy}`;
    }

    if (limit) {
      query += ` LIMIT $${paramIndex}`;
      values.push(limit);
      paramIndex++;
    }

    if (offset) {
      query += ` OFFSET $${paramIndex}`;
      values.push(offset);
      paramIndex++;
    }

    const result = await client.query(query, values);
    
    res.json({
      success: true,
      count: result.rows.length,
      data: result.rows
    });
  } catch (error) {
    console.error('Advanced search error:', error);
    res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

app.get('/api/users', async (req: Request, res: Response) => {
  try {
    const { sort, order, page, pageSize, ...filters } = req.query;
    const conditions: string[] = [];
    const values: any[] = [];
    let paramIndex = 1;

    for (const [key, value] of Object.entries(filters)) {
      if (value) {
        conditions.push(`${key} = $${paramIndex}`);
        values.push(value);
        paramIndex++;
      }
    }

    let query = 'SELECT * FROM users';
    
    if (conditions.length > 0) {
      query += ` WHERE ${conditions.join(' AND ')}`;
    }

    if (sort) {
      const sortOrder = order === 'desc' ? 'DESC' : 'ASC';
      query += ` ORDER BY ${sort} ${sortOrder}`;
    }

    if (pageSize) {
      query += ` LIMIT $${paramIndex}`;
      values.push(parseInt(pageSize as string));
      paramIndex++;
      
      if (page) {
        const offset = (parseInt(page as string) - 1) * parseInt(pageSize as string);
        query += ` OFFSET $${paramIndex}`;
        values.push(offset);
        paramIndex++;
      }
    }

    const result = await client.query(query, values);
    
    res.json({
      success: true,
      count: result.rows.length,
      data: result.rows
    });
  } catch (error) {
    console.error('Query error:', error);
    res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

